Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        // Arrange
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello world")
            });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        string result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenResponseIsError()
    {
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // Fails the test if it hangs beyond 5s
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenIsCanceled()
    {
        var handler = new MockHttpMessageHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable fake handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(HttpResponseMessage? response = null,
                                      TimeSpan delay = default)
        {
            _response = response ?? new HttpResponseMessage(HttpStatusCode.OK);
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return _response;
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `.Result` or `.GetAwaiter()` needed |
| `[Timeout(ms)]` | Guards against hangs; works cooperatively with async tests in MSTest v3+ |
| `Assert.ThrowsExactlyAsync<T>` | MSTest v3.8+ preferred over `ThrowsExceptionAsync` (exact type match, no subclass) |
| Pre-canceled `CancellationTokenSource` | Verifies the token is forwarded correctly |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over responses and delays |

> **Tip:** In MSTest v3+, `[Timeout]` uses `TestContext.CancellationTokenSource` internally. If you inject `TestContext`, you can also use `TestContext.CancellationTokenSource.Token` directly for cooperative timeout in helper methods.
